class Solution:
    def canMakeSubsequence(self, str1: str, str2: str) -> bool:
        def is_subsequence(s1, s2):
            i = j = 0
            while i < len(s1) and j < len(s2):
                if s1[i] == s2[j]:
                    j += 1
                i += 1
            return j == len(s2)

        for mask in range(1 << len(str1)):
            new_str1 = list(str1)
            for i in range(len(str1)):
                if (mask & (1 << i)):
                    new_str1[i] = chr((ord(new_str1[i]) - ord('a') + 1) % 26 + ord('a'))
            if is_subsequence(''.join(new_str1), str2):
                return True
        return False
